#include <mutex>
#include <memory>

std::mutex m_usbMutex;

void CISPDockingDlg::SendFirmwareUpdate(const std::vector<uint8_t>& data)
{
    std::scoped_lock lock(m_usbMutex);
    // critical section protected by RAII — mutex released on scope exit
    m_pDevice->Write(data.data(), data.size());
}

void CISPDockingDlg::QueryStatus()
{
    std::lock_guard<std::mutex> guard(m_usbMutex);
    m_pDevice->GetStatus();
}
